INSERT IGNORE INTO dynasties (uid, name, full_name, period, period_start, period_end, founder, last_ruler, capital, duration, highlights, description, fall_reason, legacy, population_peak, gdp_estimate, major_trade_routes, cultural_highlights) VALUES
  ('xia', '夏', NULL, '约前2070 — 前1600', -2070, -1600, '禹（姒姓）', NULL, '阳城（今河南登封）', '约470年', '中国第一个世袭制王朝、井田制、早期历法大衍历', '禹因治水有功受舜禅让即位，死后传位于子启，从此世袭制取代禅让制。夏朝定都阳城，建立军队、制定历法（夏小正）、征收赋税，设立监狱。二里头遗址被认为是夏朝中晚期都城。', '商汤伐桀于鸣条，夏朝灭亡', '九鼎象征九州，世袭制成为后世王朝传统', NULL, NULL, NULL, NULL),
  ('shang', '商', NULL, '约前1600 — 前1046', -1600, -1046, '汤（子姓）', NULL, '殷（今河南安阳）', '约554年', '甲骨文、青铜器（司母戊鼎）、神权政治、六艺', '商汤在伊尹辅佐下伐桀于鸣条建立商朝。定都殷（今河南安阳），以甲骨文和青铜器闻名于世。司母戊鼎重832.84公斤，是世界现存最大的古代青铜器。商朝已有了较完备的历法和文字系统，祭祀占卜是政治生活的重要组成部分。', '周武王牧野之战击败商纣王', '甲骨文是中国最早的文字系统，青铜器工艺登峰造极', NULL, NULL, NULL, NULL),
  ('zhou', '周', NULL, '前1046 — 前256', -1046, -256, '周武王（姬姓）', NULL, '镐京（今陕西西安）', '约790年', '礼乐制度、分封制、百家争鸣、春秋战国、诗经、论语', '周武王在牧野之战击败商纣王建立西周。实行分封制、宗法制、礼乐制度。平王东迁后进入东周（春秋战国），是中国思想文化最璀璨的时代，孔子、老子、墨子等百家争鸣。', '秦灭六国，周赧王降秦', '礼乐文明、儒家思想成为中华文明核心', NULL, NULL, NULL, NULL),
  ('qin', '秦', NULL, '前221 — 前206', -221, -206, '秦始皇（嬴姓）', NULL, '咸阳', '15年', '大一统、郡县制、万里长城、统一度量衡文字、兵马俑', '秦王嬴政扫平六国，建立中国第一个大一统中央集权帝国。废分封立郡县，统一文字（小篆）、货币（圆形方孔钱）、度量衡、车轨宽度。修筑万里长城抵御匈奴。', '秦二世暴政，陈胜吴广起义，刘邦入关中', '郡县制、大一统理念成为后世王朝模板', NULL, NULL, NULL, NULL),
  ('han', '汉', NULL, '前202 — 公元220', -202, 220, '汉高祖刘邦（姬姓）', NULL, '长安（西汉）、洛阳（东汉）', '422年', '丝绸之路、独尊儒术、史记、造纸术、强盛帝国、张骞出使', '刘邦灭项羽建立汉朝，定都长安。文景之治开创盛世。汉武帝时张骞出使西域开辟丝绸之路，董仲舒罢黜百家独尊儒术。东汉刘秀重建汉朝定都洛阳。蔡伦改进造纸术，司马迁著史记。', '黄巾起义、军阀割据，曹丕篡汉', '汉族、汉字、汉文化成为中华民族代称', NULL, NULL, NULL, NULL),
  ('sanguo', '三国', NULL, '220 — 280', 220, 280, '曹丕（姓司马）', NULL, '洛阳（魏）、成都（蜀）、建业（吴）', '60年', '群雄逐鹿、官渡之战、赤壁之战、诸葛亮、魏晋风度', '东汉末年后形成魏蜀吴三国鼎立格局。曹操统一北方推行屯田制；刘备建立蜀汉诸葛亮辅政；孙权据有江东开发江南。赤壁之战奠定三分格局。', '司马氏代魏建晋，先后灭蜀吴', '三国文化影响深远，三国演义成为世界文学经典', NULL, NULL, NULL, NULL),
  ('jin', '晋', NULL, '266 — 420', 266, 420, '晋武帝司马炎', NULL, '洛阳（西）、建康（东）', '154年', '兰亭序、王羲之书法、玄学、竹林七贤、短暂统一', '司马炎代魏建晋，短暂统一全国。西晋灭亡后东晋南渡，与北方十六国并存。书法艺术达到高峰，王羲之兰亭序被誉为天下第一行书。玄学盛行，竹林七贤风流倜傥。', '门阀政治腐败，刘裕篡晋建宋', '魏晋风度成为中国文化独特符号', NULL, NULL, NULL, NULL),
  ('nan-bei-chao', '南北朝', NULL, '420 — 589', 420, 589, '刘裕（南朝宋）/ 拓跋珪（北魏）', NULL, '建康（南朝）/ 平城、洛阳（北朝）', '169年', '民族大融合、孝文帝汉化改革、佛教兴盛、云冈龙门石窟、魏碑书法', '东晋灭亡后南方经历宋齐梁陈四朝更迭，北方由北魏统一后分裂为东西魏又演变为北齐北周。南朝文化繁荣北朝民族融合，北魏孝文帝推行汉化改革促进鲜卑等北方民族与汉族融合。佛教兴盛云冈石窟龙门石窟举世闻名，魏碑书法刚劲有力影响深远。', '隋文帝杨坚代北周灭陈统一全国', '民族大融合为隋唐盛世奠定基础，佛教文化和石窟艺术影响深远', NULL, NULL, NULL, NULL),
  ('sui', '隋', NULL, '581 — 618', 581, 618, '隋文帝杨坚', NULL, '大兴（今西安）', '37年', '科举制度、大运河、三省六部制、统一南北', '杨坚结束近四百年分裂局面建立隋朝，589年灭陈统一全国。创立三省六部制和科举制度，为后世沿用千年。隋炀帝开通大运河连接五大水系。', '隋炀帝暴政，农民起义爆发', '科举制影响中国选官制度1300年，大运河千年受益', NULL, NULL, NULL, NULL),
  ('tang', '唐', NULL, '618 — 907', 618, 907, '唐高祖李渊', NULL, '长安', '289年', '贞观之治、开元盛世、唐诗（李白杜甫）、丝绸之路、万邦来朝', '李渊建立唐朝。唐太宗开创贞观之治，唐玄宗开创开元盛世。长安城人口逾百万是世界第一大城。唐诗代表中国文学最高成就，李白杜甫白居易等诗人流传千古。', '安史之乱后藩镇割据，黄巢起义重创唐朝', '唐诗、长安文化成为中华文明最高峰象征', NULL, NULL, NULL, NULL),
  ('wu-dai-shi-guo', '五代十国', NULL, '907 — 960', 907, 960, '后梁朱温', NULL, '开封、洛阳（五代）/ 各国都城', '53年', '军阀割据、政权更迭、十国并立、南方经济开发、词的兴起', '唐朝灭亡后中原先后经历后梁后唐后晋后汉后周五个短命王朝，南方及山西存在前蜀后蜀吴南唐吴越等十国割据政权。战乱频繁但南方经济文化持续发展，南唐词学兴盛。后周世宗柴荣励精图治为统一奠定基础。石敬瑭割让燕云十六州使中原失去北方屏障。', '赵匡胤陈桥兵变代后周建宋朝，随后统一十国', '促成经济重心南移，词的兴起为宋词繁荣奠定基础', NULL, NULL, NULL, NULL),
  ('song', '宋', NULL, '960 — 1279', 960, 1279, '宋太祖赵匡胤', NULL, '汴京（北宋）、临安（南宋）', '319年', '经济文化巅峰、活字印刷、指南针、火药、清明上河图、雅致生活', '赵匡胤陈桥兵变建立北宋。宋代经济文化达到中国古代巅峰，GDP占当时世界80%以上。毕昇发明活字印刷术，指南针应用于航海，火药广泛用于军事。宋词名家辈出，瓷器工艺登峰造极。', '蒙古入侵，崖山海战南宋灭亡', '理学兴起影响东亚数百年，四大发明三项成熟于宋', NULL, NULL, NULL, NULL),
  ('yuan', '元', NULL, '1271 — 1368', 1271, 1368, '元世祖忽必烈', NULL, '大都（今北京）', '97年', '疆域最辽阔、青花瓷、马可波罗、东西方大交汇', '成吉思汗建立蒙古帝国，其孙忽必烈改国号为元，定都大都。元朝疆域东起日本海，西至天山，北包贝加尔湖，南抵南海，为中国历史上疆域最辽阔的王朝。马可·波罗游历中国。元曲兴盛。', '元末农民起义，朱元璋北伐成功', '行省制度影响至今，北京首次成为全国统一首都', NULL, NULL, NULL, NULL),
  ('ming', '明', NULL, '1368 — 1644', 1368, 1644, '明太祖朱元璋', NULL, '南京（初）、北京（后）', '276年', '郑和下西洋、紫禁城、长城修缮、小说（西游记三国演义水浒传）、资本主义萌芽', '朱元璋从起义到建立明朝，定都应天府。明成祖朱棣迁都北京修筑紫禁城，派郑和七下西洋。修筑万里长城形成今日规模。明代小说繁荣，四大名著三部成书于明代。', '李自成攻入北京，崇祯帝煤山自缢', '紫禁城、明长城成为中华文明标志，小说文化影响深远', NULL, NULL, NULL, NULL),
  ('qing', '清', NULL, '1644 — 1912', 1644, 1912, '清太宗皇太极', NULL, '北京', '268年', '康乾盛世、四库全书、近代屈辱、鸦片战争、西学东渐', '努尔哈赤建立后金，皇太极改国号为清。1644年清军入关定都北京。康熙乾隆雍正三朝开创康乾盛世历时百余年。编纂四库全书为古代最大丛书。1840年鸦片战争打开国门，最终1912年宣统帝退位封建帝制终结。', '辛亥革命爆发，清帝退位', '奠定现代中国版图基础，多民族统一国家格局形成', NULL, NULL, NULL, NULL);